                all_rows = list(ws.iter_rows(values_only=True))

                header_row_idx = 0
                for i, row in enumerate(all_rows):
                    if row and row[0] is not None:
                        s = str(row[0]).strip()
                        if len(s) < 60 and '\u2014' not in s and '\u2013' not in s:
