                           for c in all_rows[header_row_idx]]

                deal_row = None
                for row in all_rows[header_row_idx + 1:]:
                    if row and any(str(c) == '4821' for c in row if c is not None):
                        deal_row = row
                        break
                if deal_row is None:
                    continue

                row_dict = {headers[j]: deal_row[j] for j in range(min(len(headers), len(deal_row)))}

                def find_val(keys):
                    for k in headers:
                        for key in keys:
                            if key in k:
                                v = row_dict.get(k)
                                if v is not None:
                                    try:
                                        return float(v)
                                    except (ValueError, TypeError):
                                        return str(v)
                    return None

                def check_num(keys, expected, tol_pct=0.01):
                    val = find_val(keys)
                    if val is None:
                        return False, f'Field {keys[0]} not found'
                    try:
                        fval = float(val)
                    except (ValueError, TypeError):
                        return False, f'Field {keys[0]} not numeric: {val}'
                    tol = abs(expected) * tol_pct if expected != 0 else 0.01
                    if abs(fval - expected) > tol:
                        return False, f'Field {keys[0]}: expected {expected}, got {fval}'
                    return True, ''

                checks = [
                    (['sell_price', 'sellprice', 'sale_price', 'sell'], 34500),
                    (['doc_fee', 'docfee', 'doc'], 899),
                    (['tax'], 2301),
                    (['f&i_prod', 'fi_product', 'f_i_prod'], 2590),
                    (['reserve'], 1050),
                    (['down_pmt', 'down_pay', 'downpay', 'down'], 8625),
                    (['front_gross', 'frontgross', 'front'], 2000),
                    (['back_gross', 'backgross', 'back'], 3640),
                    (['total_gross', 'totalgross', 'total_g'], 5640),
                    (['desk_recap', 'deskrecap', 'desk'], 5640),
                    (['term'], 72),
                ]

                failures = []
                for keys, expected in checks:
                    ok, msg = check_num(keys, expected)
                    if not ok:
                        failures.append(msg)

                amt_val = find_val(['amt_fin', 'amount_fin', 'amtfin', 'financed'])
                if amt_val is None:
                    sp = find_val(['sell_price', 'sellprice', 'sale_price', 'sell'])
                    df = find_val(['doc_fee', 'docfee', 'doc'])
                    tx = find_val(['tax'])
                    fi = find_val(['f&i_prod', 'fi_product', 'f_i_prod'])
                    dn = find_val(['down_pmt', 'down_pay', 'downpay', 'down'])
                    if all(v is not None for v in [sp, df, tx, fi, dn]):
                        try:
                            amt_val = float(sp) + float(df) + float(tx) + float(fi) - float(dn)
                        except Exception:
                            pass
                if amt_val is None:
                    failures.append('Field amt_financed not found or not computable')
                else:
                    try:
                        if abs(float(amt_val) - 31665) > 316.65:
                            failures.append(f'Field amt_financed: expected 31665, got {amt_val}')
                    except (ValueError, TypeError):
                        failures.append(f'Field amt_financed not numeric: {amt_val}')

                var_val = find_val(['variance'])
                if var_val is None:
                    tg = find_val(['total_gross', 'totalgross', 'total_g'])
                    dr = find_val(['desk_recap', 'deskrecap', 'desk'])
                    if tg is not None and dr is not None:
                        try:
                            var_val = float(tg) - float(dr)
                        except Exception:
                            pass
                if var_val is None:
                    failures.append('Field variance not found or not computable')
                else:
                    try:
                        if abs(float(var_val) - 0) > 0.01:
                            failures.append(f'Field variance: expected 0, got {var_val}')
                    except (ValueError, TypeError):
                        failures.append(f'Field variance not numeric: {var_val}')

                apr_val = find_val(['apr', 'rate', 'int_rate'])
                if apr_val is not None:
                    try:
                        apr_f = float(apr_val)
                        if not (abs(apr_f - 0.0699) <= 0.001 or abs(apr_f - 6.99) <= 0.1):
                            failures.append(f'APR expected ~0.0699 or 6.99, got {apr_f}')
                    except (ValueError, TypeError):
                        failures.append(f'APR not numeric: {apr_val}')
                else:
                    failures.append('APR field not found')

                lender_val = find_val(['lender', 'bank', 'finance_co'])
                if lender_val is None:
                    failures.append('Lender field not found')
                elif 'ally' not in str(lender_val).lower():
                    failures.append(f'Lender expected to contain Ally, got {lender_val}')

                if failures:
                    return {'pass': False, 'score': 0.3,
                            'feedback': 'Deal #4821 found but failures: ' + '; '.join(failures)}
                return {'pass': True, 'score': 1.0,
                        'feedback': 'Deal #4821 row verified with all required fields in ' + str(xl_path.name)}

        return {'pass': False, 'score': 0.0, 'feedback': 'Deal #4821 row not found in any xlsx file'}
    except Exception as e:
